import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchComments, addComment, deleteComment } from '../../redux/thunks/postThunks';
import { NODE_API } from '../../api/config';
import { toast } from 'react-toastify';
import './CommentSection.css';

const CommentSection = ({ postId }) => {
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auth);
  const comments = useSelector((state) => state.posts.comments[postId] || []);

  useEffect(() => {
    dispatch(fetchComments({ postId, skip: 0, limit: 20 }));
  }, [dispatch, postId]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!text.trim()) return;
    setSending(true);
    const result = await dispatch(addComment({ postId, description: text.trim() }));
    setSending(false);
    if (!result.error) {
      setText('');
    } else {
      toast.error('Failed to post comment');
    }
  };

  const handleDelete = async (commentId) => {
    if (window.confirm('Delete this comment?')) {
      await dispatch(deleteComment({ commentId, postId }));
    }
  };

  const timeAgo = (dateStr) => {
    if (!dateStr) return '';
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return `${mins}m`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h`;
    const days = Math.floor(hrs / 24);
    return `${days}d`;
  };

  return (
    <div className="comment-section">
      {/* Comment input */}
      <form className="comment-input-row" onSubmit={handleSubmit}>
        {user?.imageURL ? (
          <img src={getImageUrl(user.imageURL.thumbnail || user.imageURL)} alt="" className="comment-avatar" />
        ) : (
          <div className="comment-avatar-placeholder">
            {(user?.fullName || 'U')[0].toUpperCase()}
          </div>
        )}
        <input
          type="text"
          className="comment-input"
          placeholder="Write a comment..."
          value={text}
          onChange={(e) => setText(e.target.value)}
          disabled={sending}
        />
        <button
          type="submit"
          className={`comment-send-btn ${text.trim() ? 'active' : ''}`}
          disabled={!text.trim() || sending}
        >
          ➤
        </button>
      </form>

      {/* Comments list */}
      <div className="comment-list">
        {comments.map((comment) => {
          const cUser = comment.userId || {};
          const cName = cUser.fullName || 'User';
          const cImage = getImageUrl(cUser.imageURL?.thumbnail || cUser.imageURL);
          const isOwner = user?._id === cUser._id;

          return (
            <div key={comment._id} className="comment-item">
              {cImage ? (
                <img src={cImage} alt="" className="comment-avatar" />
              ) : (
                <div className="comment-avatar-placeholder">
                  {cName[0].toUpperCase()}
                </div>
              )}
              <div className="comment-body">
                <div className="comment-bubble">
                  <span className="comment-name">{cName}</span>
                  <span className="comment-text">{comment.description}</span>
                </div>
                <div className="comment-meta">
                  <span className="comment-time">{timeAgo(comment.createdAt)}</span>
                  {isOwner && (
                    <button className="comment-delete-btn" onClick={() => handleDelete(comment._id)}>
                      Delete
                    </button>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        {comments.length === 0 && (
          <p className="comment-empty">No comments yet</p>
        )}
      </div>
    </div>
  );
};

export default CommentSection;
